import threading
from typing import Dict, Optional, Tuple
from dataclasses import dataclass, field
from enum import Enum
import uuid
import time


class TransactionType(Enum):
    DEPOSIT = "deposit"
    WITHDRAWAL = "withdrawal"
    TRANSFER = "transfer"


class TransactionStatus(Enum):
    PENDING = "pending"
    COMPLETED = "completed"
    FAILED = "failed"
    ROLLED_BACK = "rolled_back"


@dataclass
class Transaction:
    transaction_id: str
    transaction_type: TransactionType
    source_account: Optional[str]
    destination_account: Optional[str]
    amount: float
    status: TransactionStatus = TransactionStatus.PENDING
    timestamp: float = field(default_factory=time.time)
    idempotency_key: Optional[str] = None


class InsufficientFundsError(Exception):
    pass


class AccountNotFoundError(Exception):
    pass


class DuplicateTransactionError(Exception):
    pass


class FinancialProcessor:
    """
    A concurrency-safe financial transaction processor.
    
    Uses per-account locks with consistent ordering to prevent deadlocks,
    and idempotency keys to prevent duplicate processing.
    """

    def __init__(self):
        self._accounts: Dict[str, float] = {}
        self._account_locks: Dict[str, threading.Lock] = {}
        self._global_lock = threading.Lock()  # Protects account creation and lock map
        self._transaction_log: Dict[str, Transaction] = {}
        self._processed_idempotency_keys: Dict[str, str] = {}  # idempotency_key -> transaction_id
        self._idempotency_lock = threading.Lock()

    def create_account(self, account_id: str, initial_balance: float = 0.0) -> None:
        if initial_balance < 0:
            raise ValueError("Initial balance cannot be negative")
        with self._global_lock:
            if account_id in self._accounts:
                raise ValueError(f"Account {account_id} already exists")
            self._accounts[account_id] = initial_balance
            self._account_locks[account_id] = threading.Lock()

    def get_balance(self, account_id: str) -> float:
        lock = self._get_account_lock(account_id)
        with lock:
            return self._accounts[account_id]

    def _get_account_lock(self, account_id: str) -> threading.Lock:
        with self._global_lock:
            if account_id not in self._account_locks:
                raise AccountNotFoundError(f"Account {account_id} not found")
            return self._account_locks[account_id]

    def _check_and_register_idempotency(self, idempotency_key: Optional[str], transaction_id: str) -> Optional[str]:
        """
        Atomically check if an idempotency key has been used.
        Returns existing transaction_id if duplicate, None otherwise.
        Registers the key if new.
        """
        if idempotency_key is None:
            return None
        with self._idempotency_lock:
            if idempotency_key in self._processed_idempotency_keys:
                return self._processed_idempotency_keys[idempotency_key]
            self._processed_idempotency_keys[idempotency_key] = transaction_id
            return None

    def deposit(self, account_id: str, amount: float, idempotency_key: Optional[str] = None) -> Transaction:
        if amount <= 0:
            raise ValueError("Deposit amount must be positive")

        transaction_id = str(uuid.uuid4())

        # Idempotency check - atomic
        existing_txn_id = self._check_and_register_idempotency(idempotency_key, transaction_id)
        if existing_txn_id is not None:
            return self._transaction_log[existing_txn_id]

        transaction = Transaction(
            transaction_id=transaction_id,
            transaction_type=TransactionType.DEPOSIT,
            source_account=None,
            destination_account=account_id,
            amount=amount,
            idempotency_key=idempotency_key,
        )

        lock = self._get_account_lock(account_id)

        # Atomic balance update under lock
        with lock:
            self._accounts[account_id] += amount
            transaction.status = TransactionStatus.COMPLETED

        self._transaction_log[transaction_id] = transaction
        return transaction

    def withdraw(self, account_id: str, amount: float, idempotency_key: Optional[str] = None) -> Transaction:
        if amount <= 0:
            raise ValueError("Withdrawal amount must be positive")

        transaction_id = str(uuid.uuid4())

        existing_txn_id = self._check_and_register_idempotency(idempotency_key, transaction_id)
        if existing_txn_id is not None:
            return self._transaction_log[existing_txn_id]

        transaction = Transaction(
            transaction_id=transaction_id,
            transaction_type=TransactionType.WITHDRAWAL,
            source_account=account_id,
            destination_account=None,
            amount=amount,
            idempotency_key=idempotency_key,
        )

        lock = self._get_account_lock(account_id)

        # Atomic check-and-debit under a single lock hold
        with lock:
            if self._accounts[account_id] < amount:
                transaction.status = TransactionStatus.FAILED
                self._transaction_log[transaction_id] = transaction
                raise InsufficientFundsError(
                    f"Account {account_id} has insufficient funds. "
                    f"Balance: {self._accounts[account_id]}, Requested: {amount}"
                )
            self._accounts[account_id] -= amount
            transaction.status = TransactionStatus.COMPLETED

        self._transaction_log[transaction_id] = transaction
        return transaction

    def transfer(
        self,
        source_account: str,
        destination_account: str,
        amount: float,
        idempotency_key: Optional[str] = None,
    ) -> Transaction:
        if amount <= 0:
            raise ValueError("Transfer amount must be positive")
        if source_account == destination_account:
            raise ValueError("Source and destination accounts must differ")

        transaction_id = str(uuid.uuid4())

        existing_txn_id = self._check_and_register_idempotency(idempotency_key, transaction_id)
        if existing_txn_id is not None:
            return self._transaction_log[existing_txn_id]

        transaction = Transaction(
            transaction_id=transaction_id,
            transaction_type=TransactionType.TRANSFER,
            source_account=source_account,
            destination_account=destination_account,
            amount=amount,
            idempotency_key=idempotency_key,
        )

        # Acquire locks in consistent sorted order to prevent deadlocks
        lock_source = self._get_account_lock(source_account)
        lock_dest = self._get_account_lock(destination_account)

        first_lock, second_lock = (
            (lock_source, lock_dest) if source_account < destination_account
            else (lock_dest, lock_source)
        )

        # Atomic transfer: both balance check and updates under both locks
        with first_lock:
            with second_lock:
                if self._accounts[source_account] < amount:
                    transaction.status = TransactionStatus.FAILED
                    self._transaction_log[transaction_id] = transaction
                    raise InsufficientFundsError(
                        f"Account {source_account} has insufficient funds. "
                        f"Balance: {self._accounts[source_account]}, Requested: {amount}"
                    )
                self._accounts[source_account] -= amount
                self._accounts[destination_account] += amount
                transaction.status = TransactionStatus.COMPLETED

        self._transaction_log[transaction_id] = transaction
        return transaction

    def process_batch(self, transactions: list) -> list:
        """
        Process a batch of transaction descriptors.
        Each descriptor is a dict with keys: type, and relevant fields.
        """
        results = []
        for txn_desc in transactions:
            txn_type = txn_desc["type"]
            try:
                if txn_type == "deposit":
                    result = self.deposit(
                        txn_desc["account"],
                        txn_desc["amount"],
                        txn_desc.get("idempotency_key"),
                    )
                elif txn_type == "withdrawal":
                    result = self.withdraw(
                        txn_desc["account"],
                        txn_desc["amount"],
                        txn_desc.get("idempotency_key"),
                    )
                elif txn_type == "transfer":
                    result = self.transfer(
                        txn_desc["source"],
                        txn_desc["destination"],
                        txn_desc["amount"],
                        txn_desc.get("idempotency_key"),
                    )
                else:
                    raise ValueError(f"Unknown transaction type: {txn_type}")
                results.append(result)
            except (InsufficientFundsError, AccountNotFoundError, ValueError) as e:
                results.append({"error": str(e), "descriptor": txn_desc})
        return results

    def get_transaction(self, transaction_id: str) -> Optional[Transaction]:
        return self._transaction_log.get(transaction_id)

    def get_all_balances(self) -> Dict[str, float]:
        """Return a consistent snapshot of all balances."""
        with self._global_lock:
            account_ids = sorted(self._accounts.keys())
            locks = [self._account_locks[aid] for aid in account_ids]

        # Acquire all locks in sorted order
        for lock in locks:
            lock.acquire()
        try:
            return {aid: self._accounts[aid] for aid in account_ids}
        finally:
            for lock in reversed(locks):
                lock.release()


